// ---- $/RAF benchmark (demo default — set per contract; prototype used 12000) ----
export const RAF_BENCHMARK = 12000;

export interface ConfirmedCode {
  code: string;
  label: string;
  hcc: number;
  raf: number;
}

export interface CodeSuggestion {
  code: string;
  label: string;
  hcc: number;
  name?: string;
  quote?: string;
}

/** RAF coefficient for an HCC category, or null if unknown. */
export function rafOf(hcc: number | string): number | null {
  const v = HCC_RAF[String(hcc)];
  return v == null ? null : v;
}

/** "money" framing the prototype used: RAF coefficient -> approximate annual $ value. */
export function rafMoney(hcc: number | string): string {
  const v = rafOf(hcc);
  if (v == null) return "";
  const yr = v * RAF_BENCHMARK;
  return "≈$" + (yr >= 1000 ? (yr / 1000).toFixed(1) + "k" : String(Math.round(yr))) + "/yr";
}

/** Tier class used for the RAF pill colour (matches prototype thresholds). */
export function rafTier(hcc: number | string): "raf-hi" | "raf-md" | "raf-lo" | "" {
  const v = rafOf(hcc);
  if (v == null) return "";
  return v >= 1.0 ? "raf-hi" : v >= 0.4 ? "raf-md" : "raf-lo";
}

/** Human-readable RAF tag text, e.g. "💰 RAF 1.214 · ≈$14.6k/yr". */
export function rafTagText(hcc: number | string): string {
  const v = rafOf(hcc);
  if (v == null) return "";
  return (v >= 1.0 ? "💰 " : "") + "RAF " + v.toFixed(3) + " · " + rafMoney(hcc);
}

/** Look up an ICD-10 entry by code (case/dot-insensitive). */
export function icdByCode(code: string): IcdEntry | undefined {
  const k = String(code || "").toUpperCase().replace(/\./g, "");
  return ICD10.find((e) => e[0] === k);
}

/** "<label> (<code>) — HCC <n>" — the prototype's condition label format. */
export function condLabel(e: IcdEntry): string {
  return `${e[1]} (${e[0]}) — HCC ${e[2]}`;
}

/**
 * ICD-10 → V28 HCC typeahead search (ported from the prototype).
 * Matches by code prefix, then description substring, then V28 category name.
 * Highest-RAF codes surface first within each match group. Returns up to 8.
 */
export function icdSearch(q: string): IcdEntry[] {
  q = String(q || "").trim();
  if (q.length < 2) return [];
  const qu = q.toUpperCase().replace(/\./g, "");
  const ql = q.toLowerCase();
  const hits: [number, IcdEntry][] = [];
  for (const e of ICD10) {
    if (e[0].startsWith(qu)) { hits.push([0, e]); if (hits.length >= 60) break; }
  }
  if (hits.length < 8) {
    for (const e of ICD10) {
      if (e[1].toLowerCase().includes(ql)) { hits.push([1, e]); if (hits.length >= 60) break; }
    }
  }
  if (hits.length < 8) {
    const cats = Object.keys(HCC_V28).filter((k) => HCC_V28[k].toLowerCase().includes(ql));
    for (const k of cats) {
      for (const e of ICD10) {
        if (String(e[2]) === k && !hits.some((h) => h[1][0] === e[0])) {
          hits.push([2, e]); if (hits.length >= 60) break;
        }
      }
      if (hits.length >= 60) break;
    }
  }
  return hits
    .sort((a, b) => (a[0] - b[0]) || ((rafOf(b[1][2]) || 0) - (rafOf(a[1][2]) || 0)))
    .slice(0, 8)
    .map((x) => x[1]);
}

/** V28 grouping suggestions — categories often documented together, minus ones already confirmed. */
export function relatedFor(hcc: number | string, confirmed: ConfirmedCode[]): { n: number; label: string }[] {
  const rel = HCC_RELATED[String(hcc)] || [];
  return rel
    .filter((n) => HCC_V28[String(n)] && !(confirmed || []).some((c) => c.hcc === n))
    .map((n) => ({ n, label: HCC_V28[String(n)] }))
    .slice(0, 5);
}

