/**
 * Offline keyword extraction of likely HCC conditions from a transcript.
 * Ranked by RAF value, deduped against already-confirmed codes. Returns up to 8.
 */
export function scribeConditions(transcript: string, confirmed: ConfirmedCode[]): CodeSuggestion[] {
  const t = " " + String(transcript || "").toLowerCase().replace(/[,;:]/g, " ").replace(/\s+/g, " ") + " ";
  const found: CodeSuggestion[] = [];
  for (const [re, query] of CONDITION_HINTS) {
    if (re.test(t)) {
      const r = icdSearch(query)[0];
      if (
        r &&
        !found.some((f) => f.hcc === r[2]) &&
        !(confirmed || []).some((c) => c.hcc === r[2] || c.code === r[0])
      ) {
        found.push({ code: r[0], label: r[1], hcc: r[2], quote: "" });
      }
    }
  }
  found.sort((a, b) => (rafOf(b.hcc) || 0) - (rafOf(a.hcc) || 0));
  return found.slice(0, 8);
}

/** Convert an ICD entry into a ConfirmedCode (with RAF resolved, 0 if unknown). */
export function toConfirmed(e: IcdEntry): ConfirmedCode {
  return { code: e[0], label: e[1], hcc: e[2], raf: rafOf(e[2]) || 0 };
}

/** Sum of RAF across confirmed codes (one count per code; prototype framing). */
export function rafTotal(confirmed: ConfirmedCode[]): number {
  return (confirmed || []).reduce((s, c) => s + (c.raf || 0), 0);
}

/** Total annual $ value implied by a RAF total, formatted like the prototype. */
export function rafTotalMoney(total: number): string {
  const yr = total * RAF_BENCHMARK;
  return "$" + (yr >= 1000 ? (yr / 1000).toFixed(1) + "k" : String(Math.round(yr)));
}
